const forms=document.querySelectorAll(".form");forms.forEach((el)=>el.addEventListener("submit",(e)=>{e.preventDefault();const id=e.currentTarget.querySelector(".id");const valId=converterNum(id.value);if(!validarId(valId)){alternarDialogo(!0,"O ID é obrigatório e deve ser um número inteiro maior ou igual a 1. Por favor, tente novamente.");limparCampo(id);return}
e.currentTarget.submit()}))